select m.card_no as cardNo, m.name, ct.type_name as cardTypeName, ml.level_name as levelName, me.discount, me.total_points as totalPoints, m.current_points as currentPoints, me.level_points as levelPoints, case when m.status = 1 then 'T' else 'F' end as cancelled, coalesce(json_unquote(json_extract(me.excel_raw_data, '$."挂失 标记"')), '') as lostFlag, m.phone, me.total_purchase_amount as totalPurchaseAmount, me.total_purchase_count as totalPurchaseCount, me.total_purchase_times as totalPurchaseTimes, coalesce(me.join_date, date(m.created_at)) as joinDate, me.gender, me.age, m.remark, me.unit_phone as unitPhone, m.valid_date as validDate, me.wechat, me.weibo, me.superior_points_ratio as superiorPointsRatio, me.superior_name as superiorName, me.business_staff_name as businessStaffName from member m left join util_card_type ct on m.card_type_id = ct.id left join member_level ml on m.level_id = ml.id left join member_ext me on m.id = me.member_id
and m.status = #{status} and m.name like concat('%', #{name}, '%') and m.card_no like concat('%', #{cardNo}, '%') and m.phone like concat('%', #{phone}, '%') and m.dept_id = #{deptId}
and date_format(m.created_at,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')
and date_format(m.created_at,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')
${params.dataScope}
order by m.id desc

