name = #{name}, phone = #{phone}, card_type_id = #{cardTypeId}, level_id = #{levelId}, dept_id = #{deptId}, valid_date = #{validDate}, status = #{status}, borrow_count_valid = #{borrowCountValid}, current_points = #{currentPoints}, remark = #{remark}, last_operator = #{lastOperator}, updated_at = now()
